import React from 'react'
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';
import image1 from '../images/01.jpg';
import './inicio.css';

const Carrusel = () => {
  return (
    <div>
      <img src={image1} alt="Imagen 1" />
    </div>
  );
}

export default Carrusel;
